/* BTDropdownMenu styles — Figma 736-1793 (panel) + 736-1848 (item).
   All colours via @btech/tokens CSS vars — no hex fallbacks.
   Exception: drop shadow rgba values (not tokenised). */

/* ── Panel ────────────────────────────────────────────────────────────────── */
.bt-dropdown-menu__panel {
  position: fixed;
  z-index: 1000;
  background: var(--bg-primary);
  border-radius: var(--radius-xs);
  box-shadow:
    0 2px 2px rgba(0, 0, 0, 0.06),
    0 4px 3px rgba(0, 0, 0, 0.10);
  padding: var(--space-xs);
  display: flex;
  flex-direction: column;
  opacity: 0;
  pointer-events: none;
  box-sizing: border-box;
  font-family: var(--typography-font-family-sans);
}

/* Becomes visible after positionPopover() runs */
.bt-dropdown-menu__panel--visible {
  opacity: 1;
  pointer-events: auto;
}

/* ── Search area ──────────────────────────────────────────────────────────── */
.bt-dropdown-menu__search {
  padding: var(--space-xs) var(--space-xs) var(--space-sm);
  flex-shrink: 0;
}

/* ── Items scroll container ──────────────────────────────────────────────── */
.bt-dropdown-menu__items {
  max-height: 240px;
  display: flex;
  flex-direction: column;
}

/* ── Item row ────────────────────────────────────────────────────────────── */
.bt-dropdown-menu__item {
  display: flex;
  align-items: center;
  gap: var(--space-xs);
  padding: var(--space-sm);
  border-radius: var(--radius-md);
  cursor: pointer;
  user-select: none;
  color: var(--text-primary);
}

.bt-dropdown-menu__item:hover:not(.bt-dropdown-menu__item--disabled) {
  background: var(--bg-secondary);
}

.bt-dropdown-menu__item:active:not(.bt-dropdown-menu__item--disabled) {
  background: var(--bg-secondary);
}

.bt-dropdown-menu__item--error:not(.bt-dropdown-menu__item--disabled) {
  color: var(--color-ext-error);
}

.bt-dropdown-menu__item--disabled {
  color: var(--text-disabled);
  cursor: not-allowed;
}

/* ── Icon wrapper (16×16, inherits color for currentColor icons) ─────────── */
.bt-dropdown-menu__icon-wrap {
  display: flex;
  align-items: center;
  justify-content: center;
  width: 16px;
  height: 16px;
  flex-shrink: 0;
}

.bt-dropdown-menu__icon-wrap svg,
.bt-dropdown-menu__icon-wrap img {
  width: 16px;
  height: 16px;
}

/* ── Text block (label + optional subtext) ───────────────────────────────── */
.bt-dropdown-menu__item-text {
  display: flex;
  flex-direction: column;
  gap: var(--space-2xs);
  flex: 1;
  min-width: 0;
}

.bt-dropdown-menu__item-label {
  font-size: var(--typography-font-size-sm);
  font-weight: 500;
  line-height: var(--typography-line-height-xs);
}

.bt-dropdown-menu__item-subtext {
  font-size: var(--typography-font-size-xs);
  font-weight: 500;
  line-height: var(--typography-line-height-xs);
  color: var(--text-secondary);
}

/* ── Kbd shortcut badges ─────────────────────────────────────────────────── */
.bt-dropdown-menu__kbd {
  display: flex;
  gap: var(--space-2xs);
  flex-shrink: 0;
  align-items: center;
}

/* ── Group label (section header) ────────────────────────────────────────── */
.bt-dropdown-menu__group {
  padding: var(--space-sm);
  font-size: var(--typography-font-size-xs);
  font-weight: 500;
  line-height: var(--typography-line-height-xs);
  color: var(--text-secondary);
}

/* ── Separator ───────────────────────────────────────────────────────────── */
.bt-dropdown-menu__separator {
  padding: var(--space-xs) 0;
}

/**
 * BTDropdownMenu — action menu molecule (React).
 * Figma: container node 736-1793 · item node 736-1848.
 *
 * @example
 * ```tsx
 * <BTDropdownMenu
 *   items={menuItems}
 *   onSelect={handleSelect}
 *   trigger={({ toggle }) => <BTButton label="File" onClick={toggle} />}
 * />
 * ```
 */
import './BTDropdownMenu.css';
import * as React from 'react';
import { useState, useEffect, useRef, useCallback } from 'react';
import { createPortal } from 'react-dom';
import type { BTDropdownMenuEntry, BTDropdownMenuProps } from './BTDropdownMenu.types';
import { BTInputSearch } from '../input-search/BTInputSearch';
import { BTScrollbar } from '../scrollbar/BTScrollbar';
import { BTSeparator } from '../separator/BTSeparator';
import { BTKbd } from '../kbd/BTKbd';

// ── Component ─────────────────────────────────────────────────────────────────

export function BTDropdownMenu<T = string>({
  items,
  open: controlledOpen,
  hasSearch   = false,
  searchQuery = '',
  width       = 210,
  side        = 'bottom',
  align       = 'start',
  sideOffset  = 4,
  disabled    = false,
  onOpenChange,
  onSearchChange,
  onSelect,
  trigger,
}: BTDropdownMenuProps<T>) {
  const [isOpen, setIsOpen]   = useState(controlledOpen ?? false);
  const triggerRef            = useRef<HTMLSpanElement>(null);
  const panelRef              = useRef<HTMLDivElement>(null);

  // Sync controlled open
  useEffect(() => {
    if (controlledOpen !== undefined) setIsOpen(controlledOpen);
  }, [controlledOpen]);

  const close = useCallback(() => {
    setIsOpen(false);
    onOpenChange?.(false);
  }, [onOpenChange]);

  const toggle = useCallback(() => {
    if (disabled) return;
    setIsOpen(prev => {
      const next = !prev;
      onOpenChange?.(next);
      return next;
    });
  }, [disabled, onOpenChange]);

  // ── Positioning: run via rAF after portal is painted ───────────────────────
  useEffect(() => {
    if (!isOpen) return;

    function updatePosition() {
      const wrapper = triggerRef.current;
      const panel   = panelRef.current;
      if (!wrapper || !panel) return;

      // Resolve actual trigger (display:contents span → first child)
      const triggerEl = getComputedStyle(wrapper).display === 'contents'
        ? ((wrapper.firstElementChild as HTMLElement) ?? wrapper)
        : wrapper;

      const tRect = triggerEl.getBoundingClientRect();
      const pRect = panel.getBoundingClientRect();
      const vw    = window.innerWidth;
      const vh    = window.innerHeight;

      // Main axis with auto-flip
      let top  = 0;
      let left = 0;
      if (side === 'bottom') {
        const fitsBelow = vh - tRect.bottom - sideOffset >= pRect.height;
        const goAbove   = !fitsBelow && tRect.top - sideOffset >= pRect.height;
        top = goAbove ? tRect.top - pRect.height - sideOffset : tRect.bottom + sideOffset;
      } else if (side === 'top') {
        const fitsAbove = tRect.top - sideOffset >= pRect.height;
        const goBelow   = !fitsAbove && vh - tRect.bottom - sideOffset >= pRect.height;
        top = goBelow ? tRect.bottom + sideOffset : tRect.top - pRect.height - sideOffset;
      } else if (side === 'right') {
        left = tRect.right + sideOffset;
        top  = tRect.top;
      } else {
        left = tRect.left - pRect.width - sideOffset;
        top  = tRect.top;
      }

      // Cross axis alignment — flip start/end in RTL
      const isRtl = getComputedStyle(triggerEl).direction === 'rtl';
      const resolvedAlign = isRtl
        ? (align === 'start' ? 'end' : align === 'end' ? 'start' : align)
        : align;
      if (side === 'top' || side === 'bottom') {
        if      (resolvedAlign === 'start')  left = tRect.left;
        else if (resolvedAlign === 'center') left = tRect.left + tRect.width / 2 - pRect.width / 2;
        else                                 left = tRect.right - pRect.width;
        // Clamp horizontally
        left = Math.min(left, vw - 8 - pRect.width);
        left = Math.max(left, 8);
      } else {
        if      (align === 'start')  top = tRect.top;
        else if (align === 'center') top = tRect.top + tRect.height / 2 - pRect.height / 2;
        else                         top = tRect.bottom - pRect.height;
        // Clamp vertically
        top = Math.min(top, vh - 8 - pRect.height);
        top = Math.max(top, 8);
      }

      panel.style.top  = `${Math.round(top)}px`;
      panel.style.left = `${Math.round(left)}px`;
      panel.classList.add('bt-dropdown-menu__panel--visible');
    }

    const raf = requestAnimationFrame(updatePosition);
    const handleScroll = () => updatePosition();
    const handleResize = () => updatePosition();
    document.addEventListener('scroll', handleScroll, true);
    window.addEventListener  ('resize', handleResize);

    return () => {
      cancelAnimationFrame(raf);
      document.removeEventListener('scroll', handleScroll, true);
      window.removeEventListener  ('resize', handleResize);
    };
  }, [isOpen, side, align, sideOffset]);

  // ── Click-outside + Escape ────────────────────────────────────────────────
  useEffect(() => {
    if (!isOpen) return;

    function onDocClick(e: MouseEvent) {
      if (triggerRef.current?.contains(e.target as Node)) return;
      if (panelRef.current?.contains(e.target as Node)) return;
      close();
    }

    function onKeyDown(e: KeyboardEvent) {
      if (e.key === 'Escape') close();
    }

    document.addEventListener('click',   onDocClick, true);
    document.addEventListener('keydown', onKeyDown);
    return () => {
      document.removeEventListener('click',   onDocClick, true);
      document.removeEventListener('keydown', onKeyDown);
    };
  }, [isOpen, close]);

  // ── Item click ────────────────────────────────────────────────────────────
  function handleItemClick(entry: BTDropdownMenuEntry<T>) {
    if (entry.type === 'separator' || entry.type === 'group') return;
    if (entry.disabled) return;
    if (entry.value !== undefined) onSelect?.(entry.value as T);
    close();
  }

  // ── Render ────────────────────────────────────────────────────────────────
  return (
    <>
      <span ref={triggerRef} style={{ display: 'contents' }}>
        {trigger({ toggle, isOpen })}
      </span>

      {isOpen && createPortal(
        <div
          ref={panelRef}
          className="bt-dropdown-menu__panel"
          dir={triggerRef.current ? getComputedStyle(
            getComputedStyle(triggerRef.current).display === 'contents'
              ? ((triggerRef.current.firstElementChild as HTMLElement) ?? triggerRef.current)
              : triggerRef.current
          ).direction : undefined}
          style={{ width: `${width}px` }}
          role="menu"
          tabIndex={-1}
        >
          {hasSearch && (
            <div className="bt-dropdown-menu__search">
              <BTInputSearch
                value={searchQuery}
                placeholder="Search"
                onChange={onSearchChange}
              />
            </div>
          )}

          <BTScrollbar direction="y" className="bt-dropdown-menu__items" style={{ maxHeight: 240 }}>
            {items.map((entry, idx) => {
              const key = String(entry.value ?? entry.label ?? entry.type ?? idx);

              if (entry.type === 'separator') {
                return (
                  <div key={key} className="bt-dropdown-menu__separator">
                    <BTSeparator />
                  </div>
                );
              }

              if (entry.type === 'group') {
                return (
                  <div key={key} className="bt-dropdown-menu__group">
                    {entry.label}
                  </div>
                );
              }

              return (
                <div
                  key={key}
                  className={[
                    'bt-dropdown-menu__item',
                    entry.disabled ? 'bt-dropdown-menu__item--disabled' : '',
                    entry.error    ? 'bt-dropdown-menu__item--error'    : '',
                  ].filter(Boolean).join(' ')}
                  role="menuitem"
                  aria-disabled={entry.disabled ?? false}
                  onClick={() => handleItemClick(entry)}
                >
                  {entry.leftIcon != null && (
                    <span className="bt-dropdown-menu__icon-wrap">
                      {entry.leftIcon as React.ReactNode}
                    </span>
                  )}

                  <span className="bt-dropdown-menu__item-text">
                    <span className="bt-dropdown-menu__item-label">{entry.label}</span>
                    {entry.subtext && (
                      <span className="bt-dropdown-menu__item-subtext">{entry.subtext}</span>
                    )}
                  </span>

                  {(entry.kbd?.length ?? 0) > 0 && (
                    <span className="bt-dropdown-menu__kbd">
                      {entry.kbd!.map((k) => <BTKbd key={k}>{k}</BTKbd>)}
                    </span>
                  )}

                  {entry.rightIcon != null && (
                    <span className="bt-dropdown-menu__icon-wrap">
                      {entry.rightIcon as React.ReactNode}
                    </span>
                  )}
                </div>
              );
            })}
          </BTScrollbar>
        </div>,
        document.body,
      )}
    </>
  );
}

BTDropdownMenu.displayName = 'BTDropdownMenu';

/**
 * BTDropdownMenu — public API types.
 * Figma: container node 736-1793 · item node 736-1848.
 *
 * Single flat entry type — type field selects the rendered row:
 *   - 'item' (default)  — action row with icon, label, subtext, kbd, right icon
 *   - 'separator'       — thin horizontal line (BTSeparator)
 *   - 'group'           — non-interactive section label (12px, text-secondary)
 */

export type BTDropdownMenuEntryType = 'item' | 'separator' | 'group';
export type BTDropdownMenuSide      = 'top' | 'bottom' | 'left' | 'right';
export type BTDropdownMenuAlign     = 'start' | 'center' | 'end';

/**
 * One entry in the items array.
 *
 * For 'separator': only `type` is used (all other fields ignored).
 * For 'group':     only `type` + `label` are used.
 * For 'item':      all fields apply; `type` may be omitted (defaults to 'item').
 *
 * @example
 * ```ts
 * import type { BTDropdownMenuEntry } from '@btech/ui-vue';
 *
 * const items: BTDropdownMenuEntry<string>[] = [
 *   { value: 'cut',  label: 'Cut',  kbd: ['⌘', 'X'] },
 *   { value: 'copy', label: 'Copy', kbd: ['⌘', 'C'] },
 *   { type: 'separator' },
 *   { type: 'group', label: 'Danger zone' },
 *   { value: 'delete', label: 'Delete', error: true },
 * ];
 * ```
 */
export interface BTDropdownMenuEntry<T = string> {
  /** Row kind. Defaults to 'item' when absent. */
  type?: BTDropdownMenuEntryType;

  // ── Item + Group ─────────────────────────────────────────────────────────
  /** Display text. Required for 'item' and 'group'. */
  label?: string;

  /** Unique identifier returned in the 'select' emit. Required for 'item'. */
  value?: T;

  /** Secondary line below label. 'item' only. */
  subtext?: string;

  /**
   * Left icon.
   * Vue:   pass a Vue Component reference — rendered via <component :is="...">
   *        e.g. leftIcon: PhCopyIcon  (Phosphor, Material, any component)
   * React: pass a ReactNode — e.g. leftIcon: <Copy size={16} />
   */
  leftIcon?: unknown;

  /**
   * Right icon (e.g. chevron for navigation hint).
   * Same type contract as leftIcon per framework.
   */
  rightIcon?: unknown;

  /**
   * Keyboard shortcut keys rendered as BTKbd badges side-by-side.
   * e.g. ['⌘', 'X'] renders ⌘ badge + X badge.
   * 'item' only.
   */
  kbd?: string[];

  /** Dims label to text-disabled and prevents click. 'item' only. */
  disabled?: boolean;

  /**
   * Renders label in --color-ext-error.
   * Item remains clickable unless also disabled.
   * 'item' only.
   */
  error?: boolean;
}

export interface BTDropdownMenuProps<T = string> {
  /** Items to render — mix of 'item', 'group', 'separator' entries. */
  items: BTDropdownMenuEntry<T>[];

  /**
   * Controlled open state.
   * Vue: v-model:open   React: open + onOpenChange
   */
  open?: boolean;

  /**
   * Show BTInputSearch at top of panel.
   * RULE: always use BTInputSearch — never raw <input>.
   * Component does NOT auto-filter. Caller must filter items array.
   * @default false
   */
  hasSearch?: boolean;

  /**
   * Controlled search query.
   * Vue: v-model:searchQuery   React: searchQuery + onSearchChange
   * @default ''
   */
  searchQuery?: string;

  /** Panel width in px. @default 210 */
  width?: number;

  /** Panel side relative to trigger. @default 'bottom' */
  side?: BTDropdownMenuSide;

  /** Panel alignment relative to trigger. @default 'start' */
  align?: BTDropdownMenuAlign;

  /** Gap in px between trigger edge and panel. @default 4 */
  sideOffset?: number;

  /** Prevents trigger toggle — panel never opens. @default false */
  disabled?: boolean;

  // ── React callbacks + trigger ─────────────────────────────────────────────
  onOpenChange?:   (open: boolean) => void;
  onSearchChange?: (query: string) => void;
  onSelect?:       (value: T) => void;

  /**
   * Render prop that supplies the trigger element.
   * Receives { toggle, isOpen } and must return a ReactNode.
   *
   * Vue equivalent: <template #trigger="{ toggle, isOpen }"> ... </template>
   *
   * @example
   * trigger={({ toggle }) => <BTButton label="Open" onClick={toggle} />}
   */
  trigger: (props: { toggle: () => void; isOpen: boolean }) => import('react').ReactNode;
}

// ── Emits (Vue) ──────────────────────────────────────────────────────────────
// Vue emits:
//   'update:open'        (open: boolean)
//   'update:searchQuery' (query: string)
//   'select'             (value: T)
//
// Vue trigger slot:
//   <template #trigger="{ toggle, isOpen }"> ... </template>
